import { useRef, useState, useEffect } from "react";
import { useSearchParams } from "react-router-dom";
import { useMarket, useRecentlyViewed } from "@/lib/MarketContext";
import { fmt } from "@/lib/parseItem";
import { openItem } from "./DetailDrawer";
import ItemName from "./ItemName";
import { Clock, ArrowRight } from "lucide-react";

export default function RecentlyViewed({ max = 8, compact = false }) {
  const [searchParams, setSearchParams] = useSearchParams();
  const { market } = useMarket();
  const keys = useRecentlyViewed();
  const scrollerRef = useRef(null);
  // Distinguish a drag from a click: only cards > 4px movement become a scroll.
  const dragMoved = useRef(false);
  const dragStart = useRef({ x: 0, scrollLeft: 0 });
  const [dragging, setDragging] = useState(false);

  useEffect(() => {
    const el = scrollerRef.current;
    if (!el) return;
    let activePointerId = null;
    let activeKey = null;
    const onDown = (e) => {
      // Only primary button (left mouse / first touch / pen tip)
      if (e.button !== undefined && e.button !== 0) return;
      activePointerId = e.pointerId;
      // Remember which card this pointerdown started on so we can
      // open it from pointerup if the gesture turned out to be a click.
      const card = e.target.closest && e.target.closest("[data-rv-key]");
      activeKey = card ? card.getAttribute("data-rv-key") : null;
      dragMoved.current = false;
      dragStart.current = { x: e.clientX, scrollLeft: el.scrollLeft };
      setDragging(true);
      // Capture the pointer so we keep getting move/up events even if
      // the cursor leaves the scroller (fast drags).
      try { el.setPointerCapture(e.pointerId); } catch {}
      // preventDefault on pointerdown stops the inner <button> from
      // grabbing focus / starting a text selection on mousedown (the
      // thing that was blocking the drag). The trade-off is that the
      // synthetic `click` event no longer fires either, so we open
      // the item manually from pointerup below.
      e.preventDefault();
    };
    const onMove = (e) => {
      if (e.pointerId !== activePointerId) return;
      const dx = e.clientX - dragStart.current.x;
      if (Math.abs(dx) > 4) {
        dragMoved.current = true;
        el.scrollLeft = dragStart.current.scrollLeft - dx;
      }
    };
    const onUp = (e) => {
      if (e.pointerId !== activePointerId) return;
      const wasDrag = dragMoved.current;
      const clickedKey = activeKey;
      activePointerId = null;
      activeKey = null;
      dragStart.current = { x: 0, scrollLeft: 0 };
      setDragging(false);
      try { el.releasePointerCapture(e.pointerId); } catch {}
      // Treat a release with no movement past the drag threshold as
      // a click on the card the pointerdown started on.
      if (!wasDrag && clickedKey) {
        openItem(searchParams, setSearchParams, clickedKey);
      }
    };
    el.addEventListener("pointerdown", onDown);
    el.addEventListener("pointermove", onMove);
    el.addEventListener("pointerup", onUp);
    el.addEventListener("pointercancel", onUp);
    return () => {
      el.removeEventListener("pointerdown", onDown);
      el.removeEventListener("pointermove", onMove);
      el.removeEventListener("pointerup", onUp);
      el.removeEventListener("pointercancel", onUp);
    };
  }, [searchParams, setSearchParams]);

  if (!market || keys.length === 0) return null;

  const items = keys
    .map((k) => market.rowsByKey.get(k))
    .filter(Boolean)
    .slice(0, max);
  if (items.length === 0) return null;

  // Hover state is a STATIC bg shift only — no animated ring / box-shadow
  // color change, no `transition-colors` on the card itself. The earlier
  // `hover:ring-emerald-500/40` + `transition-colors` combo made sibling
  // cards re-rasterize on hover (visible as a "shiver", worse on the
  // wider w-64 Landing cards than on the w-52 compact Listings cards).
  // The inner `group-hover` text + arrow colors still animate via
  // `transition-colors` / `transition-all` on those elements, which
  // only re-paints the hovered card.
  const cardBase = "group shrink-0 snap-start text-left bg-white/[0.02] ring-1 ring-inset ring-white/10 hover:bg-white/[0.04] rounded-xl select-none";
  const cardSize = compact
    ? "w-52 p-3.5"
    : "w-64 p-4";
  const nameSize = compact ? "text-xs" : "text-sm";
  const catSize = compact ? "text-[8px]" : "text-[9px]";
  const priceGap = compact ? "mt-2.5" : "mt-3";
  const arrowSize = compact ? "w-3 h-3" : "w-3.5 h-3.5";
  const priceText = compact ? "text-xs" : "text-sm";

  return (
    <section
      data-testid="recently-viewed"
      className="relative py-6 border-t border-white/5"
    >
      <div className="max-w-7xl mx-auto px-6 md:px-12 lg:px-16">
        <div className="flex items-baseline justify-between mb-4">
          <div className="font-mono text-[11px] uppercase tracking-[0.25em] text-zinc-400 inline-flex items-center gap-2">
            <Clock className="w-3 h-3" /> Recently viewed
            <span className="hidden sm:inline-block text-zinc-700 normal-case tracking-normal text-[10px]">· drag to scroll</span>
          </div>
          <span className="font-mono text-[10px] uppercase tracking-wider text-zinc-600">last {items.length}</span>
        </div>
        <div
          ref={scrollerRef}
          className={`flex gap-3 overflow-x-auto no-scrollbar pb-2 -mx-2 px-2 snap-x ${dragging ? "cursor-grabbing" : "cursor-grab"}`}
        >
          {items.map((r) => (
            <button
              key={r.key}
              data-rv-key={r.key}
              onKeyDown={(e) => {
                if (e.key === "Enter" || e.key === " ") {
                  e.preventDefault();
                  openItem(searchParams, setSearchParams, r.key);
                }
              }}
              data-testid={`rv-${r.key}`}
              className={`${cardBase} ${cardSize} ${dragging ? "cursor-grabbing" : "cursor-grab"}`}
              style={{ WebkitUserDrag: "none" }}
            >
              <div className={`font-mono uppercase tracking-wider text-zinc-500 ${catSize}`}>{r.category}</div>
              <div className={`mt-1.5 font-heading font-bold text-white group-hover:text-emerald-400 transition-colors ${nameSize}`}>
                <ItemName name={r.name} tier={r.tier} modifiers={r.modifiers} layout="stack" className="max-w-full" />
              </div>
              <div className={`${priceGap} flex items-center justify-between`}>
                <span className={`font-mono tabular text-white ${priceText}`}>{fmt(r.median)}</span>
                <ArrowRight className={`${arrowSize} text-zinc-600 group-hover:text-emerald-400 group-hover:translate-x-0.5 transition-all`} />
              </div>
            </button>
          ))}
        </div>
      </div>
    </section>
  );
}
